mapper.select:
SELECT A.PR_NUM , A.BUYER_CD AS BUYER_CD , A.SUBJECT , (A.REQ_DATE, 'yyyyMMdd') AS REQ_DATE , A.REQ_USER_ID , GETUSERNAME(A.GATE_CD, A.REQ_USER_ID, #{ses.langCd}) AS REQ_USER_NM , GETDEPTNAME(A.GATE_CD, A.BUYER_CD, (SELECT DEPT_CD FROM STOCCVUR WHERE GATE_CD = #{ses.gateCd} AND USER_ID = A.REQ_USER_ID AND DEL_FLAG = '0'), #{ses.langCd}) AS REQ_USER_DEPT , (SELECT DEPT_CD FROM STOCCVUR WHERE GATE_CD = #{ses.gateCd} AND USER_ID = A.REQ_USER_ID AND DEL_FLAG = '0') AS REQ_USER_DEPT_CD , A.PR_TYPE , A.CUR , A.RMK_TEXT_NUM , A.ATT_FILE_NUM , A.SIGN_STATUS , (A.SIGN_DATE, 'yyyyMMdd') AS SIGN_DATE , A.APP_DOC_NUM , A.APP_DOC_CNT , PROJECT_CD , PROJECT_SQ , PROJECT_TYPE , IF_TYPE ,(SELECT MAX(PROGRESS_CD) FROM STOCPRDT WHERE GATE_CD = A.GATE_CD AND BUYER_CD = A.BUYER_CD AND PR_NUM = A.PR_NUM AND DEL_FLAG = '0') AS PRDT_MAX_PROGRESS -- M062 , A.MNT_YN FROM STOCPRHD A WHERE A.GATE_CD = #{ses.gateCd} AND A.BUYER_CD = #{BUYER_CD}
AND A.PR_NUM = #{PR_NUM}
AND A.APP_DOC_NUM = #{APP_DOC_NUM}
AND A.DEL_FLAG = '0'

SELECT PR_NUM , ITEM_CD , ITEM_DESC , ITEM_SPEC , PR_QT , UNIT_CD , (DUE_DATE, 'yyyyMMdd') AS DUE_DATE , DELY_TO_CD , DELY_TO_NM , ATT_FILE_NUM ,(SELECT COUNT(*) FROM STOCATCH WHERE GATE_CD = #{ses.gateCd} AND UUID = PRDT.ATT_FILE_NUM AND DEL_FLAG = '0') AS ATT_FILE_CNT , PRDT.CTRL_CD ,(SELECT CTRL_NM FROM STOCBACO WHERE GATE_CD = PRDT.GATE_CD AND CTRL_CD = PRDT.CTRL_CD AND DEL_FLAG = '0') AS CTRL_NM , (ITEM_RMK) AS ITEM_RMK , GETVENDORNAME(GATE_CD, VENDOR_CD, #{ses.langCd}) AS REC_VENDOR_NM , VENDOR_CD , 'R' AS INSERT_FLAG , '' AS PLAN_NUM
, TO_CHAR(PR_SQ) AS PR_SQ
, CAST(PR_SQ AS VARCHAR(6)) AS PR_SQ
, UNIT_PRC , PR_AMT ,GETMKBRNAME(PRDT.GATE_CD, PR_BUYER_CD, 'MK', PRDT.MAKER_CD) AS MAKER_NM , MAKER_CD , MAKER_PART_NO , ORIGIN_CD , DUE_DATE , DELY_TO_CD , DELY_TO_NM , ATT_FILE_NUM , ITEM_RMK , VENDOR_CD , LENGTH(VENDOR_CD) - LENGTH(REPLACE(VENDOR_CD,'{','')) AS VENDOR_CNT ,(CASE WHEN (LENGTH(VENDOR_CD) - LENGTH(REPLACE(VENDOR_CD,'{',''))) = 1 THEN JSON_VALUE(VENDOR_CD, '$.VENDOR_NM') ELSE TO_CHAR(LENGTH(VENDOR_CD) - LENGTH(REPLACE(VENDOR_CD,'{',''))) END) AS VENDOR_NM , PURCHASE_TYPE , VENDOR_OPEN_TYPE , SUBMIT_TYPE , AMT_TYPE , CTRL_CD , CTRL_USER_ID , RECEIPT_DATE ,(REJECT_RMK) REJECT_RMK , REJECT_DATE , PO_REQ_DATE , CN_DATE , RECEIPT_FLAG , LAST_VENDOR_CD , LAST_UNIT_PRC , LAST_ITEM_AMT , LAST_PO_NUM , LAST_PO_SQ , LAST_PO_FLAG , LAST_PO_CUR , MNT_SANGJU_YN , CONSUMER_AMT , FC_MNT_TERM , CH_RATE , DOIB_AMT , MNT_RATE ,(MNT_SDAY, 'yyyyMMdd') MNT_SDAY ,(MNT_EDAY, 'yyyyMMdd') MNT_EDAY , MNT_GUR_MONTH , RT_INSP_PERIOD , FALT_RC_TG_TIME , CM_REQ_ID , CM_REQ_DET_ID , MULPUM_ID , PR_BUYER_CD , PR_DEPT_CD , EC_BUYER_CD , EC_DEPT_CD ,(CASE WHEN PRDT.PR_BUYER_CD = '공동' THEN '공동' ELSE (SELECT ST.CUST_NM ||' '|| DP.DEPT_NM FROM STOCCUST ST JOIN STOCOGDP DP ON (ST.GATE_CD = DP.GATE_CD AND ST.CUST_CD = DP.BUYER_CD) WHERE DP.GATE_CD = PRDT.GATE_CD AND DP.BUYER_CD = PRDT.PR_BUYER_CD AND DP.DEPT_CD = PRDT.PR_DEPT_CD) END) AS PR_BUYER_NM ,(SELECT ST.CUST_NM ||' '|| DP.DEPT_NM FROM STOCCUST ST JOIN STOCOGDP DP ON (ST.GATE_CD = DP.GATE_CD AND ST.CUST_CD = DP.BUYER_CD) WHERE DP.GATE_CD = PRDT.GATE_CD AND DP.BUYER_CD = PRDT.EC_BUYER_CD AND DP.DEPT_CD = PRDT.EC_DEPT_CD) AS EC_BUYER_NM , CM_TYPE , CM_REQ_DET_NM , BZ_TIMELINE_SDAY , BZ_TIMELINE_EDAY , ACC_CD , ACC_HNG_NM , ACC_MOK_NM , ACC_DET_NM , BDGT_INFO , MNT_AMT , PAY_PERIOD_MTHD , PAY_PERIOD_MTHD2 , TO_CHAR(GISANIL,'YYYYMMDD') GISANIL , PROJECT_CD , PROJECT_SQ , PROJECT_TYPE , CONT_GROUND , CONT_RMK , VAT_TYPE , PRE_BUYER_CD , PRE_CONT_NUM , PRE_CONT_CNT ,(SELECT MAJOR_ITEM_FLAG FROM STOCMTGL MTGL WHERE GATE_CD = PRDT.GATE_CD AND BUYER_CD = PRDT.PR_BUYER_CD AND ITEM_CD = PRDT.ITEM_CD AND ROWNUM = 1) AS MAJOR_ITEM_FLAG FROM STOCPRDT PRDT WHERE GATE_CD = #{ses.gateCd} AND BUYER_CD = #{BUYER_CD} AND PR_NUM = #{PR_NUM}
AND PR_SQ = #{PR_SQ}
AND DEL_FLAG = '0' ORDER BY PR_SQ

SELECT SIGN_STATUS
  FROM STOCPRHD
 WHERE GATE_CD  = #{ses.gateCd}
   AND BUYER_CD = #{BUYER_CD}
   AND PR_NUM   = #{PR_NUM}
   AND DEL_FLAG = '0'

SELECT

    (MAX(TO_NUMBER(PROGRESS_CD)), 0)


    (MAX(CAST(PROGRESS_CD AS INTEGER)), 0)

  FROM STOCPRDT
 WHERE GATE_CD  = #{ses.gateCd}
   AND BUYER_CD = #{BUYER_CD}
   AND PR_NUM   = #{PR_NUM}
   AND DEL_FLAG = '0'

mapper.insert:
INSERT INTO STOCPRHD(
     GATE_CD
    ,PR_NUM
    ,BUYER_CD
    ,REG_DATE
    ,REG_USER_ID
    ,DEL_FLAG
    ,PR_TYPE
    ,SUBJECT
    ,CUR
    ,PR_AMT
    ,RMK_TEXT_NUM
    ,ATT_FILE_NUM
    ,APP_DOC_NUM
    ,APP_DOC_CNT
    ,SIGN_STATUS
    ,SIGN_DATE
    ,PROJECT_CD
    ,PROJECT_SQ
    ,REQ_DATE
    ,REQ_USER_ID
    ,DEPT_CD
)
VALUES (
     #{ses.gateCd}
    ,#{PR_NUM}
    ,#{BUYER_CD}
    ,SYSDATE
    ,#{ses.userId}
    ,'0'
    ,#{PR_TYPE}
    ,#{SUBJECT}
    ,#{CUR}
    ,#{PR_AMT}
    ,#{RMK_TEXT_NUM}
    ,#{ATT_FILE_NUM}
    ,#{APP_DOC_NUM}

    ,(CASE WHEN(#{APP_DOC_CNT}, 0) = 0 THEN 0 ELSE TO_NUMBER((#{APP_DOC_CNT}, 0)) END)


    ,(CASE WHEN #{APP_DOC_CNT} = '' THEN 0 ELSE CONVERT(INT, #{APP_DOC_CNT}) END)


    ,'P'
    ,#{SIGN_STATUS}


    ,SYSDATE
    ,NULL

    ,#{PROJECT_CD}
    ,NVL(#{PROJECT_SQ},0)
    ,#{REQ_DATE}
    ,#{ses.userId}
    ,#{ses.deptCd}
)

