mapper.update:
UPDATE STOCPRHD SET
      MOD_DATE = SYSDATE
    , MOD_USER_ID = #{ses.userId}
    , PR_TYPE = #{PR_TYPE}
    , SUBJECT = #{SUBJECT}
    , CUR = #{CUR}
    , PR_AMT = #{PR_AMT}
    , RMK_TEXT_NUM = #{RMK_TEXT_NUM}
    , ATT_FILE_NUM = #{ATT_FILE_NUM}
    , BUYER_CD = #{BUYER_CD}
    , APP_DOC_NUM = #{APP_DOC_NUM}

    , APP_DOC_CNT = (CASE WHEN (#{APP_DOC_CNT}, 0) = 0 THEN 0 ELSE TO_NUMBER((#{APP_DOC_CNT}, 0)) END)


    , APP_DOC_CNT = (CASE WHEN #{APP_DOC_CNT} = '' THEN 0 ELSE CONVERT(INT, #{APP_DOC_CNT}) END)


    , SIGN_DATE = SYSDATE



    , SIGN_STATUS = 'P'


    , SIGN_STATUS = #{SIGN_STATUS}


    , PROJECT_CD = #{PROJECT_CD}
    , PROJECT_SQ = NVL(#{PROJECT_SQ},0)
    , REQ_DATE   = #{REQ_DATE}
 WHERE GATE_CD  = #{ses.gateCd}
   AND BUYER_CD = #{BUYER_CD}
   AND PR_NUM   = #{PR_NUM}
   AND DEL_FLAG = '0'


DELETE FROM STOCPRDT
 WHERE GATE_CD  = #{ses.gateCd}
   AND BUYER_CD = #{BUYER_CD}
   AND PR_NUM   = #{PR_NUM}

UPDATE STOCPRDT SET
      MOD_DATE = SYSDATE
    , MOD_USER_ID = #{ses.userId}
    , DEL_FLAG = '1'
 WHERE GATE_CD  = #{ses.gateCd}
   AND BUYER_CD = #{BUYER_CD}
   AND PR_NUM   = #{PR_NUM}

   AND PR_SQ    = #{PR_SQ}

   AND DEL_FLAG = '0'

        UPDATE STOCPRDT SET
             MOD_DATE = SYSDATE
            ,MOD_USER_ID = #{ses.userId}
            ,ITEM_CD = #{ITEM_CD}
            ,ITEM_DESC = #{ITEM_DESC}
            ,ITEM_SPEC = #{ITEM_SPEC}
            ,PR_QT = #{PR_QT}
            ,UNIT_CD = #{UNIT_CD}

            ,UNIT_PRC = #{UNIT_PRC}
            ,PR_AMT = #{PR_AMT}


            ,UNIT_PRC = (CASE WHEN #{UNIT_PRC} = '' THEN 0 ELSE #{UNIT_PRC} END)
            ,PR_AMT = (CASE WHEN #{PR_AMT} = '' THEN 0 ELSE #{PR_AMT} END)

            ,DUE_DATE = (#{DUE_DATE}, 'yyyyMMdd')
            ,ATT_FILE_NUM = #{ATT_FILE_NUM}
            ,CTRL_CD = #{CTRL_CD}

            ,PROGRESS_CD = '2100' /* 구매요청 결재승인 = 진행상태 : 접수대기(2100) */


            ,PROGRESS_CD = '1100' /* 구매요청 NOT 결재승인 = 진행상태 : 구매요청중(1100) */

            ,ITEM_RMK = #{ITEM_RMK}

			,MAKER_CD = #{MAKER_CD}
			,MAKER_PART_NO = #{MAKER_PART_NO}
			,ORIGIN_CD = #{ORIGIN_CD}
			,DELY_TO_CD = #{DELY_TO_CD}
			,DELY_TO_NM = #{DELY_TO_NM}
			,VENDOR_CD = #{VENDOR_CD}
			,PURCHASE_TYPE = #{PURCHASE_TYPE}
			,VENDOR_OPEN_TYPE = #{VENDOR_OPEN_TYPE}
			,SUBMIT_TYPE = #{SUBMIT_TYPE}
			,AMT_TYPE = #{AMT_TYPE}
			,RECEIPT_DATE = #{RECEIPT_DATE}
			,REJECT_RMK = #{REJECT_RMK}
			,REJECT_DATE = #{REJECT_DATE}
			,PO_REQ_DATE = #{PO_REQ_DATE}
			,CN_DATE = #{CN_DATE}
			,RECEIPT_FLAG = #{RECEIPT_FLAG}
			,LAST_VENDOR_CD = #{LAST_VENDOR_CD}
			,LAST_UNIT_PRC = #{LAST_UNIT_PRC}
			,LAST_ITEM_AMT = #{LAST_ITEM_AMT}
			,LAST_PO_NUM = #{LAST_PO_NUM}
			,LAST_PO_SQ = #{LAST_PO_SQ}
			,LAST_PO_FLAG = #{LAST_PO_FLAG}
			,LAST_PO_CUR = #{LAST_PO_CUR}
			,MNT_SANGJU_YN = #{MNT_SANGJU_YN}
			,CONSUMER_AMT = #{CONSUMER_AMT}
			,FC_MNT_TERM = #{FC_MNT_TERM}
			,CH_RATE = #{CH_RATE}
			,DOIB_AMT = #{DOIB_AMT}
			,MNT_RATE = #{MNT_RATE}
			,MNT_SDAY = #{MNT_SDAY}
			,MNT_EDAY = #{MNT_EDAY}

			,MNT_GUR_MONTH = ROUNd(ABS((TO_DATE(#{MNT_SDAY},'YYYYMMDD') - TO_DATE(#{MNT_EDAY},'YYYYMMDD')) / 30),1)

			,RT_INSP_PERIOD = #{RT_INSP_PERIOD}
			,FALT_RC_TG_TIME = #{FALT_RC_TG_TIME}
			,CM_REQ_ID = #{CM_REQ_ID}
			,CM_REQ_DET_ID = #{CM_REQ_DET_ID}
			,MULPUM_ID = #{MULPUM_ID}
			,PR_BUYER_CD = #{PR_BUYER_CD}
			,PR_DEPT_CD = #{PR_DEPT_CD}
			,EC_BUYER_CD = #{EC_BUYER_CD}
			,EC_DEPT_CD = #{EC_DEPT_CD}
			,CM_TYPE = #{CM_TYPE}
			,CM_REQ_DET_NM = #{CM_REQ_DET_NM}
			,BZ_TIMELINE_SDAY = #{BZ_TIMELINE_SDAY}
			,BZ_TIMELINE_EDAY = #{BZ_TIMELINE_EDAY}
			,ACC_CD = #{ACC_CD}
			,ACC_HNG_NM = #{ACC_HNG_NM}
			,ACC_MOK_NM = #{ACC_MOK_NM}
			,ACC_DET_NM = #{ACC_DET_NM}
