			,PROJECT_TYPE = #{PROJECT_TYPE}
			,CONT_GROUND = #{CONT_GROUND}
			,CONT_RMK = #{CONT_RMK}
			,VAT_TYPE = #{VAT_TYPE}
         WHERE GATE_CD  = #{ses.gateCd}
           AND BUYER_CD = #{BUYER_CD}
           AND PR_NUM   = #{PR_NUM}
           AND PR_SQ    = #{PR_SQ}
           AND DEL_FLAG = '0'

mapper.select:
SELECT COUNT(*) FROM STOCPRDT
 WHERE GATE_CD  = #{ses.gateCd}
   AND BUYER_CD = #{BUYER_CD}
   AND PR_NUM   = #{PR_NUM}
   AND DEL_FLAG = '0'

SELECT PRDT.PR_NUM , PRDT.PR_SQ , PRDT.BUYER_CD , PRHD.SUBJECT , PRDT.PROGRESS_CD , PRDT.PURCHASE_TYPE , PRDT.ITEM_CD , PRDT.ITEM_DESC , PRDT.ITEM_SPEC ,(PRDT.DUE_DATE, 'yyyyMMdd') AS DUE_DATE , PRDT.DELY_TO_CD , PRDT.DELY_TO_NM , PRDT.ATT_FILE_NUM ,(SELECT COUNT(*) FROM STOCATCH WHERE GATE_CD = #{ses.gateCd} AND UUID = PRDT.ATT_FILE_NUM AND DEL_FLAG = '0') AS ATT_FILE_CNT ,(PRDT.ITEM_RMK) AS ITEM_RMK , PRDT.PR_QT , PRDT.UNIT_CD , PRHD.CUR , PRDT.UNIT_PRC , PRDT.PR_AMT ,GETMKBRNAME(PRDT.GATE_CD, PRDT.PR_BUYER_CD, 'MK', PRDT.MAKER_CD) AS MAKER_NM , PRDT.MAKER_CD , PRDT.MAKER_PART_NO , PRDT.ORIGIN_CD , PRDT.ITEM_RMK , PRDT.VENDOR_CD ,GETCOMPANYNAME(PRDT.GATE_CD, PRDT.VENDOR_CD, #{ses.langCd}) AS VENDOR_NM , PRDT.VENDOR_OPEN_TYPE , PRDT.SUBMIT_TYPE , PRDT.AMT_TYPE , PRDT.CTRL_CD , PRDT.CTRL_USER_ID ,GETUSERNAME(PRDT.GATE_CD, PRDT.CTRL_USER_ID, #{ses.langCd}) AS CTRL_USER_NM , PRDT.PR_BUYER_CD , PRDT.PR_DEPT_CD ,(CASE WHEN PRDT.PR_BUYER_CD = '공동' THEN '공동' ELSE getCustName(PRDT.GATE_CD, PRDT.PR_BUYER_CD) ||' '|| getDeptName(PRDT.GATE_CD, PRDT.PR_BUYER_CD, PRDT.PR_DEPT_CD, #{ses.langCd}) END) AS PR_BUYER_NM , PRDT.EC_BUYER_CD , PRDT.EC_DEPT_CD ,(SELECT ST.CUST_NM ||' '|| DP.DEPT_NM FROM STOCCUST ST JOIN STOCOGDP DP ON (ST.GATE_CD = DP.GATE_CD AND ST.CUST_CD = DP.BUYER_CD) WHERE DP.GATE_CD = PRDT.GATE_CD AND DP.BUYER_CD = PRDT.EC_BUYER_CD AND DP.DEPT_CD = PRDT.EC_DEPT_CD) AS EC_BUYER_NM , PRDT.VAT_TYPE , PRDT.RECEIPT_FLAG ,(PRDT.RECEIPT_DATE, 'yyyyMMdd') AS RECEIPT_DATE , PRDT.REJECT_DATE , PRHD.SIGN_STATUS ,GETCODENAME(#{ses.gateCd}, 'M020', PRHD.SIGN_STATUS, #{ses.langCd}) as SIGN_STATUS_NM , PRHD.REG_USER_ID ,(PRHD.REQ_DATE, 'yyyyMMdd') AS REQ_DATE ,GETUSERNAME(PRHD.GATE_CD, PRHD.REG_USER_ID, #{ses.langCd}) AS REQ_USER_NM , PRHD.IF_TYPE ,(PRHD.PR_TYPE, '10') AS PR_TYPE , PRDT.PRE_BUYER_CD , PRDT.PRE_CONT_NUM , PRDT.PRE_CONT_CNT , PRDT.CM_REQ_ID , RQDT.RFX_BUYER_CD , RQDT.RFX_NUM , RQDT.RFX_CNT , RQDT.RFX_SQ , (SELECT QTHD.QTA_NUM FROM STOCRQVN RQVN JOIN STOCQTHD QTHD ON( RQVN.GATE_CD = QTHD.GATE_CD AND RQVN.BUYER_CD = QTHD.BUYER_CD AND RQVN.RFX_NUM = QTHD.RFX_NUM AND RQVN.RFX_CNT = QTHD.RFX_CNT AND RQVN.VENDOR_CD = QTHD.VENDOR_CD AND QTHD.LAST_FLAG = '1' AND QTHD.DEL_FLAG = '0') JOIN STOCQTDT QTDT ON (QTHD.GATE_CD = QTDT.GATE_CD AND QTHD.BUYER_CD = QTDT.BUYER_CD AND QTHD.QTA_NUM = QTDT.QTA_NUM AND QTDT.QTA_SQ = RQDT.RFX_SQ AND (CASE WHEN QTDT.SETTLE_AMT IS NULL OR QTDT.SETTLE_AMT = 0 THEN 0 ELSE QTDT.SETTLE_AMT END) != 0 AND QTDT.DEL_FLAG = '0') WHERE RQDT.GATE_CD = RQVN.GATE_CD AND RQDT.RFX_BUYER_CD = RQVN.BUYER_CD AND RQDT.RFX_NUM = RQVN.RFX_NUM AND RQDT.RFX_CNT = RQVN.RFX_CNT AND RQVN.DEL_FLAG = '0') AS QTA_NUM , (SELECT QTHD.VENDOR_CD FROM STOCRQVN RQVN JOIN STOCQTHD QTHD ON( RQVN.GATE_CD = QTHD.GATE_CD AND RQVN.BUYER_CD = QTHD.BUYER_CD AND RQVN.RFX_NUM = QTHD.RFX_NUM AND RQVN.RFX_CNT = QTHD.RFX_CNT AND RQVN.VENDOR_CD = QTHD.VENDOR_CD AND QTHD.LAST_FLAG = '1' AND QTHD.DEL_FLAG = '0') JOIN STOCQTDT QTDT ON (QTHD.GATE_CD = QTDT.GATE_CD AND QTHD.BUYER_CD = QTDT.BUYER_CD AND QTHD.QTA_NUM = QTDT.QTA_NUM AND QTDT.QTA_SQ = RQDT.RFX_SQ AND (CASE WHEN QTDT.SETTLE_AMT IS NULL OR QTDT.SETTLE_AMT = 0 THEN 0 ELSE QTDT.SETTLE_AMT END) != 0 AND QTDT.DEL_FLAG = '0') WHERE RQDT.GATE_CD = RQVN.GATE_CD AND RQDT.RFX_BUYER_CD = RQVN.BUYER_CD AND RQDT.RFX_NUM = RQVN.RFX_NUM AND RQDT.RFX_CNT = RQVN.RFX_CNT AND RQVN.DEL_FLAG = '0') AS RFX_VENDOR_CD , RQDT.RFX_DATE , RQDT.RFX_SETTLE_FLAG , BDDT.BID_BUYER_CD , BDDT.BID_NUM , BDDT.BID_CNT , BDDT.BID_STATUS , BDDT.ANN_NO , BDDT.BID_SETTLE_FLAG , BDDT.BID_DATE , BDDT.BID_VENDOR_CD ,(SELECT VENDOR_NM FROM STOCVNGL WHERE GATE_CD = PRDT.GATE_CD AND VENDOR_CD= BDDT.BID_VENDOR_CD) AS BID_VENDOR_NM , CNDT.EXEC_BUYER_CD , CNDT.EXEC_NUM , CNDT.EXEC_DATE , CONT.CONT_BUYER_CD , CONT.CONT_NUM , CONT.CONT_CNT , CONT.CONT_DATE , CONT.CONT_VENDOR_CD ,(SELECT VENDOR_NM FROM STOCVNGL WHERE GATE_CD = PRDT.GATE_CD AND VENDOR_CD= CONT.CONT_VENDOR_CD) AS CONT_VENDOR_NM ,((SELECT SUM(PODT.PO_QT) FROM STOCPODT PODT JOIN STOCPOHD POHD ON (PODT.GATE_CD = POHD.GATE_CD AND PODT.BUYER_CD = POHD.BUYER_CD AND PODT.PO_NUM = POHD.PO_NUM AND POHD.PROGRESS_CD = '5200' -- 협력사발주접수 AND POHD.DEL_FLAG = '0') WHERE PODT.GATE_CD = PRDT.GATE_CD AND PODT.PB_BUYER_CD = PRDT.BUYER_CD AND PODT.PR_NUM = PRDT.PR_NUM AND PODT.PR_SQ = PRDT.PR_SQ AND PODT.DEL_FLAG = '0'), '0') AS PO_QT ,((SELECT SUM(PODT.ITEM_AMT) FROM STOCPODT PODT JOIN STOCPOHD POHD ON (PODT.GATE_CD = POHD.GATE_CD AND PODT.BUYER_CD = POHD.BUYER_CD AND PODT.PO_NUM = POHD.PO_NUM AND POHD.PROGRESS_CD = '5200' -- 협력사발주접수 AND POHD.DEL_FLAG = '0') WHERE PODT.GATE_CD = PRDT.GATE_CD AND PODT.PB_BUYER_CD = PRDT.BUYER_CD AND PODT.PR_NUM = PRDT.PR_NUM AND PODT.PR_SQ = PRDT.PR_SQ AND PODT.DEL_FLAG = '0'), '0') AS PO_AMT ,((SELECT SUM(IVDT.INV_QT) FROM STOCPODT PODT JOIN STOCPOHD POHD ON (PODT.GATE_CD = POHD.GATE_CD AND PODT.BUYER_CD = POHD.BUYER_CD AND PODT.PO_NUM = POHD.PO_NUM AND POHD.PROGRESS_CD = '5200' -- 협력사발주접수 AND POHD.DEL_FLAG = '0') JOIN STOCIVDT IVDT ON (PODT.GATE_CD = IVDT.GATE_CD AND PODT.BUYER_CD = IVDT.BUYER_CD AND PODT.PO_NUM = IVDT.PO_NUM AND PODT.PO_SQ = IVDT.PO_SQ AND IVDT.DEL_FLAG = '0') JOIN STOCIVHD IVHD ON (IVDT.GATE_CD = IVHD.GATE_CD AND IVDT.BUYER_CD = IVHD.BUYER_CD AND IVDT.INV_NUM = IVHD.INV_NUM AND IVHD.PROGRESS_CD IN ('700', '300') -- 검수승인 AND IVHD.DEL_FLAG = '0') WHERE PODT.GATE_CD = PRDT.GATE_CD AND PODT.PB_BUYER_CD = PRDT.BUYER_CD AND PODT.PR_NUM = PRDT.PR_NUM AND PODT.PR_SQ = PRDT.PR_SQ AND PODT.DEL_FLAG = '0'), '0') AS INV_QT ,((SELECT SUM(IVDT.ITEM_AMT) FROM STOCPODT PODT JOIN STOCPOHD POHD ON (PODT.GATE_CD = POHD.GATE_CD AND PODT.BUYER_CD = POHD.BUYER_CD AND PODT.PO_NUM = POHD.PO_NUM AND POHD.PROGRESS_CD = '5200' -- 협력사발주접수 AND POHD.DEL_FLAG = '0') JOIN STOCIVDT IVDT ON (PODT.GATE_CD = IVDT.GATE_CD AND PODT.BUYER_CD = IVDT.BUYER_CD AND PODT.PO_NUM = IVDT.PO_NUM AND PODT.PO_SQ = IVDT.PO_SQ AND IVDT.DEL_FLAG = '0') JOIN STOCIVHD IVHD ON (IVDT.GATE_CD = IVHD.GATE_CD AND IVDT.BUYER_CD = IVHD.BUYER_CD AND IVDT.INV_NUM = IVHD.INV_NUM AND IVHD.PROGRESS_CD IN ('700', '300') -- 검수승인 AND IVHD.DEL_FLAG = '0') WHERE PODT.GATE_CD = PRDT.GATE_CD AND PODT.PB_BUYER_CD = PRDT.BUYER_CD AND PODT.PR_NUM = PRDT.PR_NUM AND PODT.PR_SQ = PRDT.PR_SQ AND PODT.DEL_FLAG = '0'), '0') AS INV_AMT , '■' AS PROG_01 , '■' AS PROG_02 , '■' AS PROG_03 , '■' AS PROG_04 , '■' AS PROG_05 , '■' AS PROG_06 , '■' AS PROG_07 FROM STOCPRDT PRDT JOIN STOCPRHD PRHD ON (PRDT.GATE_CD = PRHD.GATE_CD AND PRDT.BUYER_CD = PRHD.BUYER_CD AND PRDT.PR_NUM = PRHD.PR_NUM AND PRHD.DEL_FLAG = '0') LEFT JOIN (SELECT A.GATE_CD, A.PB_BUYER_CD, A.PR_NUM, A.PR_SQ , B.BUYER_CD AS RFX_BUYER_CD, B.RFX_NUM, B.RFX_CNT, B.RFX_START_DATE AS RFX_DATE, A.RFX_SQ ,(CASE WHEN B.PROGRESS_CD = '2500' AND A.SETTLE_DATE IS NOT NULL THEN '300' WHEN B.PROGRESS_CD = '1300' THEN '400' ELSE null END) AS RFX_SETTLE_FLAG , ROW_NUMBER() OVER (PARTITION BY A.GATE_CD, A.PB_BUYER_CD, A.PR_NUM, A.PR_SQ ORDER BY B.RFX_NUM DESC, B.RFX_CNT DESC) AS RNUM FROM STOCRQDT A JOIN STOCRQHD B ON (B.GATE_CD = A.GATE_CD AND B.BUYER_CD = A.BUYER_CD AND B.RFX_NUM = A.RFX_NUM AND B.RFX_CNT = A.RFX_CNT AND ((TO_NUMBER(B.PROGRESS_CD) >= 2300 AND TO_NUMBER(B.PROGRESS_CD) <= 2500) -- 견적/입찰 작성중(2300), 낙찰(2500) OR TO_NUMBER(B.PROGRESS_CD) = 1300) -- 유찰 AND B.DEL_FLAG = '0') WHERE A.GATE_CD = #{ses.gateCd} AND A.DEL_FLAG = '0' GROUP BY A.GATE_CD, A.PB_BUYER_CD, A.PR_NUM, A.PR_SQ , B.BUYER_CD, B.RFX_NUM, B.RFX_CNT, B.RFX_START_DATE, B.PROGRESS_CD, A.SETTLE_DATE, A.RFX_SQ) RQDT ON (PRDT.GATE_CD = RQDT.GATE_CD AND PRDT.BUYER_CD = RQDT.PB_BUYER_CD AND PRDT.PR_NUM = RQDT.PR_NUM AND PRDT.PR_SQ = RQDT.PR_SQ AND RQDT.RNUM = 1) LEFT JOIN (SELECT A.GATE_CD, A.PB_BUYER_CD, A.PR_NUM, A.PR_SQ , B.BUYER_CD AS BID_BUYER_CD, B.BID_NUM, B.BID_CNT, B.ANN_NO, B.ANN_DATE AS BID_DATE ,(CASE WHEN B.BID_STATUS = '2500' THEN '300' WHEN B.BID_STATUS = '1300' THEN '400' ELSE null END) AS BID_SETTLE_FLAG ,(CASE WHEN B.BID_STATUS = '2500' THEN MAX(C.VENDOR_CD) ELSE null END) AS BID_VENDOR_CD , B.BID_STATUS , ROW_NUMBER() OVER (PARTITION BY A.GATE_CD, A.PB_BUYER_CD, A.PR_NUM, A.PR_SQ ORDER BY B.BID_NUM DESC, B.BID_CNT DESC) AS RNUM FROM STOCBDDT A JOIN STOCBDHD B ON (A.GATE_CD = B.GATE_CD AND A.BUYER_CD = B.BUYER_CD AND A.BID_NUM = B.BID_NUM AND A.BID_CNT = B.BID_CNT AND B.SIGN_STATUS = 'E' AND B.BID_STATUS NOT IN ('2303', '9999') -- 취소공고작성중, 취소공고확정 제외 AND ((TO_NUMBER(B.BID_STATUS) >= 2300 AND TO_NUMBER(B.BID_STATUS) <= 2500) -- 견적/입찰 작성중(2300), 낙찰(2500) OR TO_NUMBER(B.BID_STATUS) = 1300) -- 유찰 AND B.DEL_FLAG = '0') LEFT JOIN STOCBDVO C ON (A.GATE_CD = C.GATE_CD AND A.BUYER_CD = C.BUYER_CD AND A.BID_NUM = C.BID_NUM AND A.BID_CNT = C.BID_CNT AND C.BID_STATUS = '300' -- 협력사선정 AND C.DEL_FLAG = '0') WHERE A.GATE_CD = #{ses.gateCd} AND A.DEL_FLAG = '0' GROUP BY A.GATE_CD, A.PB_BUYER_CD, A.PR_NUM, A.PR_SQ , B.BUYER_CD, B.BID_NUM, B.BID_CNT, B.ANN_NO, B.ANN_DATE, B.BID_STATUS) BDDT ON (PRDT.GATE_CD = BDDT.GATE_CD AND PRDT.BUYER_CD = BDDT.PB_BUYER_CD AND PRDT.PR_NUM = BDDT.PR_NUM AND PRDT.PR_SQ = BDDT.PR_SQ AND BDDT.RNUM = 1) LEFT JOIN (SELECT A.GATE_CD, A.PB_BUYER_CD, A.PR_NUM, A.PR_SQ , B.BUYER_CD AS EXEC_BUYER_CD, B.EXEC_NUM, B.EXEC_DATE , ROW_NUMBER() OVER (PARTITION BY A.GATE_CD, A.PB_BUYER_CD, A.PR_NUM, A.PR_SQ ORDER BY B.EXEC_NUM DESC) AS RNUM FROM STOCCNDT A JOIN STOCCNHD B ON (A.GATE_CD = B.GATE_CD AND A.BUYER_CD = B.BUYER_CD AND A.EXEC_NUM = B.EXEC_NUM AND B.DEL_FLAG = '0') WHERE A.GATE_CD = #{ses.gateCd} AND A.PROGRESS_CD IN ('3100', '3200') -- 품의중, 품의완료 AND A.DEL_FLAG = '0' GROUP BY A.GATE_CD, A.PB_BUYER_CD, A.PR_NUM, A.PR_SQ , B.BUYER_CD, B.EXEC_NUM, B.EXEC_DATE) CNDT ON (PRDT.GATE_CD = CNDT.GATE_CD AND PRDT.BUYER_CD = CNDT.PB_BUYER_CD AND PRDT.PR_NUM = CNDT.PR_NUM AND PRDT.PR_SQ = CNDT.PR_SQ AND CNDT.RNUM = 1) LEFT JOIN (SELECT A.GATE_CD, A.PB_BUYER_CD, A.PR_NUM, A.PR_SQ , B.BUYER_CD AS CONT_BUYER_CD, B.CONT_NUM, B.CONT_CNT, B.CONT_DATE, B.VENDOR_CD AS CONT_VENDOR_CD , ROW_NUMBER() OVER (PARTITION BY A.GATE_CD, A.PB_BUYER_CD, A.PR_NUM, A.PR_SQ ORDER BY B.CONT_NUM DESC, B.CONT_CNT DESC) AS RNUM FROM STOCECMT A JOIN STOCECCT B ON (A.GATE_CD = B.GATE_CD AND A.BUYER_CD = B.BUYER_CD AND A.CONT_NUM = B.CONT_NUM AND A.CONT_CNT = B.CONT_CNT AND B.DEL_FLAG = '0') WHERE A.GATE_CD = #{ses.gateCd} AND A.DEL_FLAG = '0' GROUP BY A.GATE_CD, A.PB_BUYER_CD, A.PR_NUM, A.PR_SQ , B.BUYER_CD, B.CONT_NUM, B.CONT_CNT, B.CONT_DATE, B.VENDOR_CD) CONT ON (PRDT.GATE_CD = CONT.GATE_CD AND PRDT.BUYER_CD = CONT.PB_BUYER_CD AND PRDT.PR_NUM = CONT.PR_NUM AND PRDT.PR_SQ = CONT.PR_SQ AND CONT.RNUM = 1) WHERE PRDT.GATE_CD = #{ses.gateCd} AND PRDT.DEL_FLAG = '0'
AND PRHD.BUYER_CD in ( #{ses.companyCd}, '공동')
AND (PRHD.BUYER_CD = #{ses.companyCd} OR PRDT.EC_BUYER_CD = #{ses.companyCd})
AND PRHD.REQ_DATE >= (#{REQ_DATE_FROM}) AND PRHD.REQ_DATE <= (#{REQ_DATE_TO})
AND UPPER(REPLACE(PRHD.SUBJECT, ' ', '')) LIKE '%' UPPER(REPLACE(#{PR_SUBJECT}, ' ', '')) '%'
AND UPPER(PRHD.PR_NUM) LIKE '%' UPPER(#{PR_NUM}) '%'
AND PRDT.PURCHASE_TYPE = #{PURCHASE_TYPE}
AND PRDT.PROGRESS_CD = #{PROGRESS_CD}
AND PRHD.SIGN_STATUS = #{SIGN_STATUS}
AND PRHD.REQ_USER_ID = #{REQ_USER_ID}
AND GETUSERNAME(PRHD.GATE_CD, PRHD.REQ_USER_ID, #{ses.langCd}) LIKE '%' #{REQ_USER_NM} '%'
AND PRDT.EC_BUYER_CD = #{EC_BUYER_CD}
AND PRDT.EC_DEPT_CD = #{EC_DEPT_CD}
AND GETBUYERDEPTNAME(PRDT.GATE_CD, PRDT.EC_BUYER_CD, PRDT.EC_DEPT_CD, #{ses.langCd}) LIKE '%' #{EC_BUYER_NM} '%'
AND PRDT.ITEM_CD LIKE '%' UPPER(#{ITEM_CD}) '%'
AND PRDT.ITEM_DESC LIKE '%' UPPER(#{ITEM_DESC}) '%'
AND PRDT.CTRL_USER_ID LIKE '%' UPPER(#{CTRL_USER_ID}) '%'
AND GETUSERNAME(PRDT.GATE_CD, PRDT.CTRL_USER_ID, #{ses.langCd}) LIKE '%' #{CTRL_USER_NM} '%'
AND PRDT.CM_REQ_ID LIKE '%' UPPER(#{CM_REQ_ID}) '%'
ORDER BY PRHD.REQ_DATE DESC , PRDT.PR_NUM DESC , PRDT.PR_SQ

